    val businessOrder = listOf("electronics", "grocery", "pharmacy", "restaurant")
    val validCoupons = mutableListOf<Pair<String, String>>()

    for (i in code.indices) {
        if (!isActive[i]) continue
        val codeStr = code[i]
        val businessStr = businessLine[i]

        // Check if code is valid (non-empty, only alphanumeric and underscore)
