            continue
        }

        validCoupons.add(Pair(businessStr, codeStr))
    }

    // Sort by business line order and then by code in dictionary order
    validCoupons.sortBy { pair -> pair.first.toInt() * 1000 + pair.second.compareTo("") }

    // Extract the codes in the sorted order
    return validCoupons.map { it.second }.toTypedArray()
}
